function getDefaultsHTML(){const e=window.state.cbSettings||{};return`\n        <div class="fade-in">\n            <h3 style="color: var(--primary-color); margin-bottom: 1rem;">\n                <i class="fa-solid fa-sliders"></i> System Defaults\n            </h3>\n            <div style="background: white; padding: 1.5rem; border-radius: 8px; border: 1px solid var(--border-color);">\n                <form id="defaults-form" style="max-width: 600px;">\n                    <div class="form-group">\n                        <label>Date Format</label>\n                        <select id="cb-date-format" class="form-control">\n                            <option value="YYYY-MM-DD" ${"YYYY-MM-DD"===e.dateFormat?"selected":""}>YYYY-MM-DD (2024-01-15)</option>\n                            <option value="DD/MM/YYYY" ${"DD/MM/YYYY"===e.dateFormat?"selected":""}>DD/MM/YYYY (15/01/2024)</option>\n                            <option value="MM/DD/YYYY" ${"MM/DD/YYYY"===e.dateFormat?"selected":""}>MM/DD/YYYY (01/15/2024)</option>\n                        </select>\n                    </div>\n\n                    <div class="form-group">\n                        <label>Currency</label>\n                        <select id="cb-currency" class="form-control">\n                            <option value="USD" ${"USD"===e.currency?"selected":""}>USD - US Dollar ($)</option>\n                            <option value="EUR" ${"EUR"===e.currency?"selected":""}>EUR - Euro (€)</option>\n                            <option value="GBP" ${"GBP"===e.currency?"selected":""}>GBP - British Pound (£)</option>\n                            <option value="INR" ${"INR"===e.currency?"selected":""}>INR - Indian Rupee (₹)</option>\n                            <option value="PKR" ${"PKR"===e.currency?"selected":""}>PKR - Pakistani Rupee (₨)</option>\n                            <option value="AUD" ${"AUD"===e.currency?"selected":""}>AUD - Australian Dollar (A$)</option>\n                            <option value="CAD" ${"CAD"===e.currency?"selected":""}>CAD - Canadian Dollar (C$)</option>\n                            <option value="CNY" ${"CNY"===e.currency?"selected":""}>CNY - Chinese Yuan (¥)</option>\n                            <option value="JPY" ${"JPY"===e.currency?"selected":""}>JPY - Japanese Yen (¥)</option>\n                            <option value="CHF" ${"CHF"===e.currency?"selected":""}>CHF - Swiss Franc (Fr)</option>\n                            <option value="SGD" ${"SGD"===e.currency?"selected":""}>SGD - Singapore Dollar (S$)</option>\n                            <option value="AED" ${"AED"===e.currency?"selected":""}>AED - UAE Dirham (د.إ)</option>\n                            <option value="SAR" ${"SAR"===e.currency?"selected":""}>SAR - Saudi Riyal (﷼)</option>\n                            <option value="ZAR" ${"ZAR"===e.currency?"selected":""}>ZAR - South African Rand (R)</option>\n                            <option value="BRL" ${"BRL"===e.currency?"selected":""}>BRL - Brazilian Real (R$)</option>\n                            <option value="MXN" ${"MXN"===e.currency?"selected":""}>MXN - Mexican Peso ($)</option>\n                            <option value="NZD" ${"NZD"===e.currency?"selected":""}>NZD - New Zealand Dollar (NZ$)</option>\n                            <option value="KRW" ${"KRW"===e.currency?"selected":""}>KRW - South Korean Won (₩)</option>\n                            <option value="SEK" ${"SEK"===e.currency?"selected":""}>SEK - Swedish Krona (kr)</option>\n                            <option value="NOK" ${"NOK"===e.currency?"selected":""}>NOK - Norwegian Krone (kr)</option>\n                            <option value="DKK" ${"DKK"===e.currency?"selected":""}>DKK - Danish Krone (kr)</option>\n                        </select>\n                    </div>\n\n                    <div class="form-group">\n                        <label>Certificate Number Format</label>\n                        <input type="text" id="cb-cert-format" class="form-control" \n                               value="${e.certificateNumberFormat||"CB-{YEAR}-{SEQ}"}" \n                               placeholder="CB-{YEAR}-{SEQ}">\n                        <small class="form-text">Use {YEAR} for year, {SEQ} for sequence number</small>\n                    </div>\n\n                    <div class="form-group">\n                        <label>Default Stage 1 Duration (days)</label>\n                        <input type="number" id="cb-stage1-duration" class="form-control" \n                               value="${e.defaultStage1Duration||1}" min="1">\n                    </div>\n\n                    <div class="form-group">\n                        <label>Default Stage 2 Duration (days)</label>\n                        <input type="number" id="cb-stage2-duration" class="form-control" \n                               value="${e.defaultStage2Duration||2}" min="1">\n                    </div>\n\n                    <div class="form-group">\n                        <label>Man-Day Calculation Mode</label>\n                        <select id="cb-manday-mode" class="form-control">\n                            <option value="ISO 17021" ${"ISO 17021"===e.manDayCalculationMode?"selected":""}>ISO 17021</option>\n                            <option value="Custom" ${"Custom"===e.manDayCalculationMode?"selected":""}>Custom</option>\n                        </select>\n                    </div>\n\n                    <div class="form-group">\n                        <label>Notification Lead Time (days)</label>\n                        <input type="number" id="cb-notification-leadtime" class="form-control" \n                               value="${e.notificationLeadTime||14}" min="1">\n                    </div>\n\n                    <div class="form-group">\n                        <label>Session Timeout (minutes)</label>\n                        <input type="number" id="cb-session-timeout" class="form-control" \n                               value="${e.sessionTimeout||30}" min="5">\n                    </div>\n\n                    <button type="button" class="btn btn-primary" data-action="saveDefaultSettings" aria-label="Save">\n                        <i class="fa-solid fa-save"></i> Save Settings\n                    </button>\n                </form>\n            </div>\n        </div>\n    `}async function saveDefaultSettings(){try{window.state.cbSettings.dateFormat=document.getElementById("cb-date-format").value,window.state.cbSettings.currency=document.getElementById("cb-currency").value,window.state.cbSettings.certificateNumberFormat=document.getElementById("cb-cert-format").value,window.state.cbSettings.defaultStage1Duration=parseInt(document.getElementById("cb-stage1-duration",10).value,10),window.state.cbSettings.defaultStage2Duration=parseInt(document.getElementById("cb-stage2-duration",10).value,10),window.state.cbSettings.manDayCalculationMode=document.getElementById("cb-manday-mode").value,window.state.cbSettings.notificationLeadTime=parseInt(document.getElementById("cb-notification-leadtime",10).value,10),window.state.cbSettings.sessionTimeout=parseInt(document.getElementById("cb-session-timeout",10).value,10),window.saveData(),await window.DataService.syncSettings({saveLocal:!1}),window.showNotification("System defaults saved successfully","success")}catch(e){console.error("Failed to save defaults:",e),window.showNotification("Failed to save settings","error")}}window.saveDefaultSettings=saveDefaultSettings,"undefined"!=typeof module&&module.exports&&(module.exports=saveDefaultSettings);